class Solution:
    def breakPalindrome(self, palindrome: str) -> str:
        n = len(palindrome)
        if n == 1:
            return ''
        chars = list(palindrome)
        for i in range(n):
            if chars[i] != 'a' and not (n % 2 == 1 and i == n // 2):
                chars[i] = 'a'
                return ''.join(chars)
        chars[-1] = 'b'
        return ''.join(chars)

