var breakPalindrome = function(palindrome) {
    const n = palindrome.length;
    if (n === 1) return '';
    const chars = palindrome.split('');
    for (let i = 0; i < n; i++) {
        if (chars[i] !== 'a' && !(n % 2 === 1 && i === Math.floor(n / 2))) {
            chars[i] = 'a';
            return chars.join('');
        }
    }
    chars[n - 1] = 'b';
    return chars.join('');
};
